{"code": "import json

# Load data
def load_data(var):
    value = var
    if isinstance(value, str) and value.endswith('.json'):
        with open(value, 'r') as f:
            return json.load(f)
    elif isinstance(value, list):
        return value
    else:
        return []

# Load MIT packages from packageinfo
mit_packages = load_data(var_functions.query_db:14)
print('MIT release packages count:', len(mit_packages))

# Load project_packageversion data
project_packages = load_data(var_functions.query_db:20)
print('Project packages count:', len(project_packages))

# Sample data
print('First 3 MIT packages:', mit_packages[:3])
print('First 3 project packages:', project_packages[:3])"}

