{"code": "import json

# Load data
def load_data(var):
    value = var
    if isinstance(value, str) and value.endswith('.json'):
        with open(value, 'r') as f:
            return json.load(f)
    elif isinstance(value, list):
        return value
    else:
        return []

# Load MIT packages from packageinfo
